+import { type AnyColumn } from '~/column.ts';
+import { type SQL, sql, type SQLWrapper } from '../sql.ts';
+
+type ExpressionData<T extends SQLWrapper> = T extends AnyColumn ? T['_']['data']
+	: T extends SQL<infer TData> ? TData
+	: unknown;
+
+type ValueData<T> = T extends SQLWrapper ? ExpressionData<T> : T;
+
+export type WindowOrderBy = SQLWrapper;
+
+export type WindowFrameBoundary =
+	| { readonly kind: 'unbounded preceding' }
+	| { readonly kind: 'current row' }
+	| { readonly kind: 'unbounded following' }
+	| { readonly kind: 'preceding'; readonly value: number }
+	| { readonly kind: 'following'; readonly value: number };
+
+export interface WindowFrame {
+	readonly kind: 'rows' | 'range';
+	readonly from: WindowFrameBoundary;
+	readonly to: WindowFrameBoundary;
+}
+
+export interface WindowSpec {
+	partitionBy?: WindowOrderBy | WindowOrderBy[];
+	orderBy?: WindowOrderBy | WindowOrderBy[];
+	frame?: WindowFrame;
+}
+
+export const unboundedPreceding: WindowFrameBoundary = { kind: 'unbounded preceding' };
+export const currentRow: WindowFrameBoundary = { kind: 'current row' };
+export const unboundedFollowing: WindowFrameBoundary = { kind: 'unbounded following' };
+
+function assertFrameOffset(name: 'preceding' | 'following', value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	}
+}
+
+export function preceding(value: number): WindowFrameBoundary {
+	assertFrameOffset('preceding', value);
+	return { kind: 'preceding', value };
+}
+
+export function following(value: number): WindowFrameBoundary {
+	assertFrameOffset('following', value);
+	return { kind: 'following', value };
+}
+
+function framePosition(boundary: WindowFrameBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return -Infinity;
+		case 'preceding': return -boundary.value;
+		case 'current row': return 0;
+		case 'following': return boundary.value;
+		case 'unbounded following': return Infinity;
+	}
+}
+
+function createFrame(kind: WindowFrame['kind'], spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	if (framePosition(spec.from) > framePosition(spec.to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after the "to" boundary');
+	}
+	return { kind, ...spec };
+}
+
+export function rows(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	return createFrame('rows', spec);
+}
+
+export function range(spec: { from: WindowFrameBoundary; to: WindowFrameBoundary }): WindowFrame {
+	return createFrame('range', spec);
+}
+
+function boundarySQL(boundary: WindowFrameBoundary): SQL {
+	switch (boundary.kind) {
+		case 'preceding': return sql.raw(`${boundary.value} preceding`);
+		case 'following': return sql.raw(`${boundary.value} following`);
+		default: return sql.raw(boundary.kind);
+	}
+}
+
+function frameSQL(frame: WindowFrame): SQL {
+	return sql` ${sql.raw(frame.kind)} between ${boundarySQL(frame.from)} and ${boundarySQL(frame.to)}`;
+}
+
+function windowSpecSQL(spec: WindowSpec): SQL {
+	const partitionBy = spec.partitionBy === undefined ? [] : (Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy]);
+	const orderBy = spec.orderBy === undefined ? [] : (Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy]);
+	const partitionBySQL = partitionBy.length ? sql`partition by ${sql.join(partitionBy, sql`, `)}` : undefined;
+	const orderBySQL = orderBy.length ? sql`order by ${sql.join(orderBy, sql`, `)}` : undefined;
+	const separator = partitionBySQL && orderBySQL ? sql` ` : undefined;
+	return sql`${partitionBySQL}${separator}${orderBySQL}${spec.frame ? frameSQL(spec.frame) : undefined}`;
+}
+
+export class WindowFunction<T> {
+	constructor(private readonly expression: SQL) {}
+
+	over(): SQL<T>;
+	over(spec: WindowSpec): SQL<T>;
+	over(windowName: string): SQL<T>;
+	over(specOrName?: WindowSpec | string): SQL<T> {
+		if (typeof specOrName === 'string') {
+			return sql`${this.expression} over ${sql.identifier(specOrName)}` as SQL<T>;
+		}
+		return sql`${this.expression} over (${windowSpecSQL(specOrName ?? {})})` as SQL<T>;
+	}
+}
+
+function functionCall<T>(name: string, args: SQL[]): WindowFunction<T> {
+	return new WindowFunction<T>(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positional(value: number): SQL {
+	return sql.raw(String(value));
+}
+
+function positiveInteger(name: 'ntile' | 'nthValue', value: number): void {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() requires a positive integer, received ${value}`);
+	}
+}
+
+export function rowNumber(): WindowFunction<number> { return functionCall('row_number', []); }
+export function rank(): WindowFunction<number> { return functionCall('rank', []); }
+export function denseRank(): WindowFunction<number> { return functionCall('dense_rank', []); }
+export function percentRank(): WindowFunction<number> { return functionCall('percent_rank', []); }
+export function cumeDist(): WindowFunction<number> { return functionCall('cume_dist', []); }
+
+export function ntile(buckets: number): WindowFunction<number> {
+	positiveInteger('ntile', buckets);
+	return functionCall('ntile', [positional(buckets)]);
+}
+
+export function lag<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null>;
+export function lag<T extends SQLWrapper>(expression: T, offset: number): WindowFunction<ExpressionData<T> | null>;
+export function lag<T extends SQLWrapper, TDefault>(expression: T, offset: number, defaultValue: TDefault): WindowFunction<Exclude<ExpressionData<T>, null> | ValueData<TDefault>>;
+export function lag(expression: SQLWrapper, offset?: number, defaultValue?: unknown): WindowFunction<unknown> {
+	const args = [expression.getSQL(), ...(offset === undefined ? [] : [positional(offset)]), ...(defaultValue === undefined ? [] : [defaultValue instanceof Object && 'getSQL' in defaultValue ? (defaultValue as SQLWrapper).getSQL() : sql`${defaultValue}`])];
+	return functionCall('lag', args);
+}
+
+export function lead<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null>;
+export function lead<T extends SQLWrapper>(expression: T, offset: number): WindowFunction<ExpressionData<T> | null>;
+export function lead<T extends SQLWrapper, TDefault>(expression: T, offset: number, defaultValue: TDefault): WindowFunction<Exclude<ExpressionData<T>, null> | ValueData<TDefault>>;
+export function lead(expression: SQLWrapper, offset?: number, defaultValue?: unknown): WindowFunction<unknown> {
+	const args = [expression.getSQL(), ...(offset === undefined ? [] : [positional(offset)]), ...(defaultValue === undefined ? [] : [defaultValue instanceof Object && 'getSQL' in defaultValue ? (defaultValue as SQLWrapper).getSQL() : sql`${defaultValue}`])];
+	return functionCall('lead', args);
+}
+
+export function firstValue<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return functionCall('first_value', [expression.getSQL()]); }
+export function lastValue<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return functionCall('last_value', [expression.getSQL()]); }
+export function nthValue<T extends SQLWrapper>(expression: T, n: number): WindowFunction<ExpressionData<T> | null> {
+	positiveInteger('nthValue', n);
+	return functionCall('nth_value', [expression.getSQL(), positional(n)]);
+}
+export function windowSum<T extends SQLWrapper>(expression: T): WindowFunction<string | null> { return functionCall('sum', [expression.getSQL()]); }
+export function windowAvg<T extends SQLWrapper>(expression: T): WindowFunction<string | null> { return functionCall('avg', [expression.getSQL()]); }
+export function windowMin<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return functionCall('min', [expression.getSQL()]); }
+export function windowMax<T extends SQLWrapper>(expression: T): WindowFunction<ExpressionData<T> | null> { return functionCall('max', [expression.getSQL()]); }
+export function windowCount(expression?: SQLWrapper): WindowFunction<number> { return functionCall('count', [expression ? expression.getSQL() : sql.raw('*')]); }
